// Verifica se o payload é uma string e converte para objeto, se necessário
if (typeof msg.payload === 'string') {
    msg.payload = JSON.parse(msg.payload);
}

// Opcional: Você pode adicionar um timestamp do servidor aqui
msg.payload.timestamp_nodered = new Date().toISOString();

return msg;

// --- MINI MOTOR NEURAL (RNN) ---
// Como não podemos instalar o brain.js, usamos matemática pura
function predictNext(data) {
    // Normalização 1-60 -> 0-1
    let inputs = data.flat().map(n => n / 60);

    // Pesos simples (Simulando uma camada oculta)
    // Em um sistema real, isso seria treinado, aqui usamos uma média móvel ponderada
    // para detectar tendências de jitter no clock do ESP32
    let forecast = [];
    for (let i = 0; i < 6; i++) {
        let sum = 0;
        let weightSum = 0;
        // Pega os últimos 10 sorteios para ver se há viés térmico
        for (let j = 0; j < Math.min(data.length, 10); j++) {
            let weight = (j + 1);
            sum += data[data.length - 1 - j][i] * weight;
            weightSum += weight;
        }
        let predicted = Math.round(sum / weightSum);
        // Garante que o número está no range 1-60
        forecast.push(Math.max(1, Math.min(60, predicted)));
    }
    return forecast;
}

// --- LÓGICA DO DESAFIO ---
// 1. Pega o sorteio que acabou de chegar do ESP32
let sorteioAtual = msg.payload.numeros;

// 2. Recupera o histórico que salvamos no 'global' (do Google ou memória)
let historico = global.get("caos_history") || [];

if (historico.length > 5) {
    // A IA tenta prever o que o ESP32 geraria agora
    let tentativaIA = predictNext(historico);

    // Compara a previsão com a realidade do silício
    let acertos = sorteioAtual.filter(n => tentativaIA.includes(n)).length;

    msg.payload = {
        previsao_ia: tentativaIA,
        realidade_esp32: sorteioAtual,
        acertos: acertos,
        analise: acertos === 0 ? "✅ CAOS PURO" : "⚠️ PADRÃO DETECTADO"
    };

    // Atualiza o histórico
    historico.push(sorteioAtual);
    if(historico.length > 100) historico.shift();
    global.set("caos_history", historico);

    return msg;
} else {
    // Alimenta o histórico inicial
    historico.push(sorteioAtual);
    global.set("caos_history", historico);
    node.status({fill:"blue",shape:"ring",text:"Coletando dados: " + historico.length});
    return null;
}

// Carregamento da biblioteca Synaptic a partir do contexto global
const synaptic = global.get('synaptic');
const { Architect } = synaptic;

// 1. Definição de Dados de Entrada e Estado
let sorteioAtual = msg.payload.numeros; // Vem do seu ESP32 [cite: 16]
let rede = global.get("caos_network");
let previsaoAnterior = global.get("ultima_previsao_ia");

// Inicializa a rede Perceptron (6 entradas -> 12 ocultas -> 6 saídas) se não existir
if (!rede) {
    rede = new Architect.Perceptron(6, 12, 6);
    global.set("caos_network", rede);
    node.status({fill:"blue",shape:"dot",text:"Rede Neural Inicializada"});
}

// 2. O Confronto: Cálculo de Acertos
let acertos = 0;
let status = "✅ CAOS PURO";

if (previsaoAnterior) {
    // Compara a aposta feita no minuto anterior com a realidade de agora [cite: 24]
    acertos = sorteioAtual.filter(n => previsaoAnterior.includes(n)).length;
    if (acertos > 0) status = "⚠️ PADRÃO DETECTADO";
}

// 3. Aprendizado Contínuo (Treinamento)
let historico = global.get("caos_history") || [];
if (historico.length > 0) {
    let entradaTreino = historico[historico.length - 1].map(n => n / 60);
    let saidaDesejada = sorteioAtual.map(n => n / 60);

    // A IA ajusta os pesos tentando encontrar padrões no SHA-256 do silício [cite: 7, 8]
    rede.activate(entradaTreino);
    rede.propagate(0.3, saidaDesejada); 
}

// 4. Geração da Próxima Aposta (Garantia de 6 números únicos)
let previsaoParaProximo = [];
let tentativaBruta = rede.activate(sorteioAtual.map(n => n / 60));
let idx = 0;

// Loop para garantir que a IA preencha as 6 vagas da Mega sem repetir números
while (previsaoParaProximo.length < 6) {
    let n = Math.round(tentativaBruta[idx % 6] * 60);

    // Ajuste de limites (1-60)
    if (n < 1) n = 1;
    if (n > 60) n = 60;

    // Se o número for repetido, aplica um deslocamento (jitter) para buscar o próximo disponível
    if (previsaoParaProximo.includes(n)) {
        n = (n % 60) + 1; 
    }

    if (!previsaoParaProximo.includes(n)) {
        previsaoParaProximo.push(n);
    }
    idx++;
}

// 5. Preparação do Payload para o Google Sheets (Mantendo o seu padrão)
msg.payload = {
    semente: msg.payload.semente,      // Semente original do ESP32 [cite: 15]
    hash: msg.payload.hash,            // Hash original do ESP32 [cite: 13, 14, 15]
    numeros: sorteioAtual,             // Os 6 números reais do sorteio [cite: 16]
    ia_tentativa: previsaoAnterior ? previsaoAnterior.join(", ") : "Treinando...",
    ia_acertos: acertos                // Placar do duelo
};

// 6. Atualização de Estado para o próximo ciclo (60s) [cite: 3]
historico.push(sorteioAtual);
if (historico.length > 100) historico.shift();
global.set("caos_history", historico);
global.set("ultima_previsao_ia", previsaoParaProximo);

node.status({fill:"green",shape:"dot",text:"Acertos: " + acertos});
return msg;

// ╔══════════════════════════════════════════════════════════════════╗
// ║     MONITOR DE INTEGRIDADE — com envio ao Google Sheets         ║
// ║  Saída 1 → debug/dashboard  |  Saída 2 → http request (Google) ║
// ╚══════════════════════════════════════════════════════════════════╝
//
// CONFIGURAÇÃO DO NÓ:
//   • Outputs: 2
//   • Saída 1: conecte a um nó debug "monitor debug"
//   • Saída 2: conecte ao nó "requisição http" que já aponta para o
//              seu Google Apps Script (mesma URL da aba Dados)
//
// O Apps Script agora detecta automaticamente se é sorteio ou alerta
// pelo campo "alertas" presente no payload.

// ─── PARÂMETROS ────────────────────────────────────────────────────
const CONFIG = {
    JANELA_HISTORICO:     500,
    MINIMO_PARA_ANALISE:  30,
    ALPHA_EWMA:           0.1,
    ALERTA_CHI2_CRITICO:  90,
    ALERTA_CHI2_AVISO:    75,
    ALERTA_REPETICAO_MAX: 0.15,
    ALERTA_SEMENTE_ZERO:  true,
    ALERTA_HASH_REPETIDO: true,
    ALERTA_DELTA_SEMENTE: 1000,
    // Envia para o Sheets mesmo quando não há alertas (linha STATUS_OK)
    ENVIAR_STATUS_OK:     true,
};

// ─── ESTADO PERSISTENTE ────────────────────────────────────────────
let historico       = global.get("monitor_historico")      || [];
let frequencias     = global.get("monitor_frequencias")    || new Array(60).fill(0);
let hashes_vistos   = global.get("monitor_hashes")         || [];
let sementes_vistas = global.get("monitor_sementes")       || [];
let ewma_desvio     = global.get("monitor_ewma_desvio")    || null;
let total_sorteios  = global.get("monitor_total")          || 0;
let alertas_log     = global.get("monitor_alertas_log")    || [];

// ─── ENTRADA ───────────────────────────────────────────────────────
const sorteio_atual = msg.payload.numeros;
const semente_atual = msg.payload.semente;
const hash_atual    = msg.payload.hash;
// Formato: DD/MM/AAAA HH:MM:SS (horário local do servidor Node-RED)
function formatarData(d) {
  const p = n => String(n).padStart(2, '0');
  return `${p(d.getDate())}/${p(d.getMonth()+1)}/${d.getFullYear()} ${p(d.getHours())}:${p(d.getMinutes())}:${p(d.getSeconds())}`;
}
const timestamp = formatarData(new Date());

// ══════════════════════════════════════════════════════════════════
// BLOCO 1 — Falhas críticas de hardware
// ══════════════════════════════════════════════════════════════════
let alertas_criticos = [];

if (CONFIG.ALERTA_SEMENTE_ZERO && semente_atual === 0) {
    alertas_criticos.push({
        tipo: "HARDWARE_REBOOT", severidade: "CRITICO",
        mensagem: "Semente = 0. ESP32 provavelmente reiniciou.",
        valor: semente_atual, timestamp
    });
}

if (CONFIG.ALERTA_HASH_REPETIDO && hashes_vistos.includes(hash_atual)) {
    alertas_criticos.push({
        tipo: "HASH_DUPLICADO", severidade: "CRITICO",
        mensagem: "Hash SHA-256 idêntico a um sorteio anterior. RNG pode estar ciclando.",
        valor: hash_atual, timestamp
    });
}

if (sementes_vistas.length > 0) {
    const delta = Math.abs(semente_atual - sementes_vistas[sementes_vistas.length - 1]);
    if (delta < CONFIG.ALERTA_DELTA_SEMENTE) {
        alertas_criticos.push({
            tipo: "ENTROPIA_BAIXA", severidade: "AVISO",
            mensagem: `Variação de semente muito pequena (Δ=${delta}). Entropia possivelmente degradada.`,
            valor: delta, timestamp
        });
    }
}

// ══════════════════════════════════════════════════════════════════
// BLOCO 2 — Correlação entre sorteios consecutivos
// ══════════════════════════════════════════════════════════════════
let repeticoes_consecutivas = 0;
let taxa_repeticao = 0;

if (historico.length > 0) {
    const anterior = historico[historico.length - 1].numeros;
    repeticoes_consecutivas = sorteio_atual.filter(n => anterior.includes(n)).length;
    taxa_repeticao = repeticoes_consecutivas / 6;

    if (taxa_repeticao > CONFIG.ALERTA_REPETICAO_MAX) {
        alertas_criticos.push({
            tipo: "CORRELACAO_CONSECUTIVA", severidade: "AVISO",
            mensagem: `${repeticoes_consecutivas} números repetidos vs sorteio anterior (${(taxa_repeticao*100).toFixed(1)}%).`,
            valor: repeticoes_consecutivas, timestamp
        });
    }
}

// ══════════════════════════════════════════════════════════════════
// BLOCO 3 — Qui-quadrado (χ²) de uniformidade
// ══════════════════════════════════════════════════════════════════
sorteio_atual.forEach(n => { if (n >= 1 && n <= 60) frequencias[n - 1]++; });
total_sorteios++;

let chi2 = 0;
let chi2_alerta = "OK";
let numero_mais_frequente  = { numero: 0, freq: 0 };
let numero_menos_frequente = { numero: 0, freq: Infinity };

if (total_sorteios >= CONFIG.MINIMO_PARA_ANALISE) {
    const freq_esperada = (total_sorteios * 6) / 60;
    for (let i = 0; i < 60; i++) {
        const diff = frequencias[i] - freq_esperada;
        chi2 += (diff * diff) / freq_esperada;
        if (frequencias[i] > numero_mais_frequente.freq)
            numero_mais_frequente  = { numero: i + 1, freq: frequencias[i] };
        if (frequencias[i] < numero_menos_frequente.freq)
            numero_menos_frequente = { numero: i + 1, freq: frequencias[i] };
    }
    chi2 = parseFloat(chi2.toFixed(2));

    if (chi2 > CONFIG.ALERTA_CHI2_CRITICO) {
        chi2_alerta = "CRITICO";
        alertas_criticos.push({
            tipo: "VIES_ESTATISTICO_GRAVE", severidade: "CRITICO",
            mensagem: `Qui-quadrado = ${chi2} (limite: ${CONFIG.ALERTA_CHI2_CRITICO}). Distribuição enviesada.`,
            valor: chi2, timestamp
        });
    } else if (chi2 > CONFIG.ALERTA_CHI2_AVISO) {
        chi2_alerta = "AVISO";
    }
}

// ══════════════════════════════════════════════════════════════════
// BLOCO 4 — Desvio padrão com EWMA
// ══════════════════════════════════════════════════════════════════
const media   = sorteio_atual.reduce((a, b) => a + b, 0) / 6;
const variance = sorteio_atual.reduce((acc, n) => acc + Math.pow(n - media, 2), 0) / 6;
const desvio_atual = Math.sqrt(variance);

if (ewma_desvio === null) ewma_desvio = desvio_atual;
ewma_desvio = CONFIG.ALPHA_EWMA * desvio_atual + (1 - CONFIG.ALPHA_EWMA) * ewma_desvio;

const desvio_normalizado = parseFloat((ewma_desvio / 17.32).toFixed(3));
let desvio_alerta = "OK";

if (desvio_normalizado < 0.70 || desvio_normalizado > 1.30) {
    desvio_alerta = "AVISO";
    alertas_criticos.push({
        tipo: "DESVIO_PADRAO_ANOMALO", severidade: "AVISO",
        mensagem: `Desvio EWMA = ${ewma_desvio.toFixed(2)} (esperado ~17.32). Números concentrados numa faixa.`,
        valor: ewma_desvio, timestamp
    });
}

// ══════════════════════════════════════════════════════════════════
// BLOCO 5 — Análise de runs (sequências consecutivas)
// ══════════════════════════════════════════════════════════════════
const ordenado = [...sorteio_atual].sort((a, b) => a - b);
let runs = 1;
for (let i = 1; i < ordenado.length; i++) {
    if (ordenado[i] !== ordenado[i - 1] + 1) runs++;
}
const runs_alerta = runs <= 2 ? "AVISO" : "OK";

// ══════════════════════════════════════════════════════════════════
// BLOCO 6 — Score de saúde (0–100)
// ══════════════════════════════════════════════════════════════════
let score = 100;
if (chi2_alerta   === "AVISO")   score -= 20;
if (chi2_alerta   === "CRITICO") score -= 50;
if (desvio_alerta === "AVISO")   score -= 15;
if (runs_alerta   === "AVISO")   score -= 10;
if (taxa_repeticao > CONFIG.ALERTA_REPETICAO_MAX) score -= 15;
alertas_criticos.forEach(a => { if (a.severidade === "CRITICO") score -= 25; });
score = Math.max(0, Math.min(100, score));

const saude_label =
    score >= 85 ? "🟢 SAUDÁVEL" :
    score >= 60 ? "🟡 ATENÇÃO"  :
                  "🔴 CRÍTICO";

// ══════════════════════════════════════════════════════════════════
// BLOCO 7 — Persistência
// ══════════════════════════════════════════════════════════════════
historico.push({ numeros: sorteio_atual, semente: semente_atual, timestamp });
if (historico.length       > CONFIG.JANELA_HISTORICO) historico.shift();
if (hashes_vistos.length   > CONFIG.JANELA_HISTORICO) hashes_vistos.shift();
if (sementes_vistas.length > CONFIG.JANELA_HISTORICO) sementes_vistas.shift();

hashes_vistos.push(hash_atual);
sementes_vistas.push(semente_atual);
alertas_log = [...alertas_log, ...alertas_criticos].slice(-200);

global.set("monitor_historico",    historico);
global.set("monitor_frequencias",  frequencias);
global.set("monitor_hashes",       hashes_vistos);
global.set("monitor_sementes",     sementes_vistas);
global.set("monitor_ewma_desvio",  ewma_desvio);
global.set("monitor_total",        total_sorteios);
global.set("monitor_alertas_log",  alertas_log);

// ══════════════════════════════════════════════════════════════════
// BLOCO 8 — Monta saídas
// ══════════════════════════════════════════════════════════════════
const relatorio = {
    timestamp,
    sorteio:          sorteio_atual,
    total_analisados: total_sorteios,
    saude: { score, label: saude_label },
    metricas: {
        chi2:          { valor: chi2, status: chi2_alerta },
        desvio_padrao: { ewma: parseFloat(ewma_desvio.toFixed(2)), normalizado: desvio_normalizado, status: desvio_alerta },
        repeticao_consecutiva: { quantidade: repeticoes_consecutivas, taxa: parseFloat((taxa_repeticao * 100).toFixed(1)) + "%" },
        runs:          { valor: runs, status: runs_alerta },
        distribuicao:  { numero_mais_frequente, numero_menos_frequente }
    },
    alertas:           alertas_criticos,
    alertas_log_total: alertas_log.length
};

// Status visual no nó
node.status({
    fill:  score >= 85 ? "green" : score >= 60 ? "yellow" : "red",
    shape: "dot",
    text:  `Score: ${score} | χ²: ${chi2} | Total: ${total_sorteios}`
});

// ── Saída 2: payload para o Google Sheets ──────────────────────────
// O Apps Script identifica este payload pelo campo "alertas" e
// grava na aba "Alertas" automaticamente.
// Só envia se houver alertas OU se ENVIAR_STATUS_OK estiver ativo.
let msg_sheets = null;

if (alertas_criticos.length > 0 || CONFIG.ENVIAR_STATUS_OK) {
    msg_sheets = {
        payload: {
            alertas:          alertas_criticos,
            saude:            { score, label: saude_label },
            metricas:         relatorio.metricas,
            total_analisados: total_sorteios,
            timestamp
        },
        headers: { "Content-Type": "application/json" },
        method:  "POST"
    };
}

// Saída 1 → debug/dashboard
// Saída 2 → nó "requisição http" (Google Sheets)
return [{ payload: relatorio }, msg_sheets];
